// Process each want list item
const items = Array.isArray($json) ? $json : [$json];
return items.map(item => ({json: item}));

// Aggregate and rank results
const gutenberg = $input.getByIndex(0)?.json?.results || [];
const openlibrary = $input.getByIndex(1)?.json?.docs || [];
const archive = $input.getByIndex(2)?.json?.response?.docs || [];

const query = $json.search_query.toLowerCase();

const candidates = [
  ...gutenberg.map(book => ({
    title: book.title,
    author: book.authors?.[0]?.name || 'Unknown',
    source: 'gutenberg',
    source_url: book.cover_image || '',
    formats: book.formats,
    confidence: 0.9
  })),
  ...openlibrary.map(book => ({
    title: book.title,
    author: book.author_name?.[0] || 'Unknown',
    source: 'openlibrary',
    source_url: book.key || '',
    confidence: 0.7
  })),
  ...archive.map(book => ({
    title: book.title,
    author: book.creator ? (Array.isArray(book.creator) ? book.creator[0] : book.creator) : 'Unknown',
    source: 'archive',
    source_url: book.identifier || '',
    confidence: 0.8
  }))
];

const best = candidates.sort((a, b) => b.confidence - a.confidence)[0];

if (!best) {
  return {json: {
    found: false,
    reason: 'no_results',
    search_query: $json.search_query
  }};
}

let downloadUrl = null;
if (best.source === 'gutenberg' && best.formats) {
  const pdf = Object.entries(best.formats).find(([key]) => key.includes('pdf') || key.includes('epub'));
  downloadUrl = pdf ? pdf[1] : null;
}

return {json: {
  ...best,
  found: !!downloadUrl,
  download_url: downloadUrl,
  category: $json.subject_category || 'Fiction'
}};

if (!$json.found || !$json.download_url) {
  return {json: {
    valid: false,
    error: $json.reason || 'no_download_url',
    title: $json.title || $json.search_query
  }};
}

const filename = `${$json.title}_${$json.author}`.replace(/[<>:"|?*]/g, '_').substring(0, 200);
const category = $json.category || 'uncategorized';
const filepath = `/home/lewis/aegis/library/${category}/${filename}.pdf`;

return {json: {
  title: $json.title,
  author: $json.author,
  source: $json.source,
  download_url: $json.download_url,
  filepath: filepath,
  category: category,
  confidence: $json.confidence,
  found: true
}};
